import { uuidv7 } from '@motivation/shared';
import type { ClientLogEntry, LogLevel, LogsResponse } from '@motivation/shared';
import { appendEntries, getRecentClientLogs, queryClientLogs } from './client-log-store.js';
import { getDeviceId, getDeviceLabel } from './device-identity.js';
import { extractModule } from '../../utils/component-logger.js';

export interface ClientLogInput {
    level: LogLevel;
    module: string;
    message: string;
    context?: Record<string, unknown>;
}

const DEFAULT_FLUSH_MS = 250;

interface BatcherOptions {
    flushMs?: number;
    /** Hook fired after a successful flush — used to trigger background sync. */
    onFlush?: (count: number) => void;
}

class ClientLogBatcher {
    private buffer: ClientLogEntry[] = [];
    private flushHandle: ReturnType<typeof setTimeout> | null = null;
    private readonly flushMs: number;
    private readonly onFlush: ((count: number) => void) | undefined;

    constructor(options: BatcherOptions = {}) {
        this.flushMs = options.flushMs ?? DEFAULT_FLUSH_MS;
        this.onFlush = options.onFlush;
    }

    push(input: ClientLogInput): void {
        const entry: ClientLogEntry = {
            id: uuidv7(),
            timestamp: Temporal.Now.instant().toString(),
            level: input.level,
            module: input.module,
            message: input.message,
            device_id: getDeviceId(),
            device_label: getDeviceLabel(),
            ...(input.context ? { context: input.context } : {}),
        };
        this.buffer.push(entry);
        this.scheduleFlush();
    }

    private scheduleFlush(): void {
        if (this.flushHandle != null) return;
        this.flushHandle = setTimeout(() => {
            this.flushHandle = null;
            void this.flushNow();
        }, this.flushMs);
    }

    async flushNow(): Promise<void> {
        if (this.flushHandle != null) {
            clearTimeout(this.flushHandle);
            this.flushHandle = null;
        }
        if (this.buffer.length === 0) return;
        const batch = this.buffer;
        this.buffer = [];
        try {
            await appendEntries(batch);
            this.onFlush?.(batch.length);
        } catch (error) {
            // If the IDB write fails, keep the entries in memory so a later
            // flush can retry. We don't surface to the user — the next call
            // either succeeds or we lose them on tab close. Acceptable for
            // a developer logging tool.
            this.buffer = [...batch, ...this.buffer];
            throw error;
        }
    }

    /** Test-only: drop pending entries without flushing. */
    drainForTests(): ClientLogEntry[] {
        if (this.flushHandle != null) {
            clearTimeout(this.flushHandle);
            this.flushHandle = null;
        }
        const out = this.buffer;
        this.buffer = [];
        return out;
    }
}

let singleton: ClientLogBatcher | null = null;
let installed = false;
let cleanupFns: Array<() => void> = [];

function getBatcher(options?: BatcherOptions): ClientLogBatcher {
    if (!singleton) singleton = new ClientLogBatcher(options);
    return singleton;
}

/** Read recent entries from IndexedDB for the Debug screen's live view. */
export function getRecentClientLogsResponse(limit = 500): Promise<LogsResponse> {
    return getRecentClientLogs(limit);
}

/** Filtered query used by the `<log-viewer>` source on the Debug screen. */
export function queryRecentClientLogs(filters: { level?: LogLevel[]; search?: string }): Promise<LogsResponse> {
    return queryClientLogs(filters);
}

/** Force-flush the pending batch (used on `pagehide`). Returns the number flushed. */
export async function flushClientLogBatch(): Promise<void> {
    if (singleton) await singleton.flushNow();
}

/**
 * Push a single entry into the client-log batcher. Used by the Debug screen
 * to leave visible markers (e.g. after a "Clear buffer" press).
 */
export function pushClientLogEntry(input: ClientLogInput): void {
    getBatcher().push(input);
}

function defaultOnFlush(): void {
    // Fire-and-forget: a registration failure (no SW yet, no Background
    // Sync) is surfaced through the Debug screen's status check, not here.
    void import('./client-log-shipping.js').then(m => m.requestClientLogSync()).catch(() => undefined);
}

export interface InstallOptions extends BatcherOptions {
    batcher?: ClientLogBatcher;
}

const CONSOLE_METHODS: Array<{ name: 'log' | 'info' | 'warn' | 'error' | 'debug'; level: LogLevel }> = [
    { name: 'log',   level: 'info' },
    { name: 'info',  level: 'info' },
    { name: 'warn',  level: 'warn' },
    { name: 'error', level: 'error' },
    { name: 'debug', level: 'debug' },
];

export function installConsoleCapture(options: InstallOptions = {}): ClientLogBatcher {
    const onFlush = options.onFlush ?? defaultOnFlush;
    const batcher = options.batcher ?? getBatcher({ flushMs: options.flushMs, onFlush });
    if (options.batcher) singleton = options.batcher;

    if (installed) return batcher;
    installed = true;

    for (const { name, level } of CONSOLE_METHODS) {
        const original = console[name].bind(console);
        const patched = (...args: unknown[]) => {
            const { module, cleanArgs } = extractModule(args, 'client');
            try {
                batcher.push(buildEntryFromArgs(level, module, cleanArgs));
            } catch {
                // Never let the logger crash the app.
            }
            original(...cleanArgs);
        };
        console[name] = patched as typeof console[typeof name];
        cleanupFns.push(() => { console[name] = original as typeof console[typeof name]; });
    }

    const onError = (event: ErrorEvent) => {
        const err = event.error;
        const message = event.message || (err instanceof Error ? err.message : String(err));
        const context: Record<string, unknown> = {};
        if (event.filename) context.filename = event.filename;
        if (typeof event.lineno === 'number') context.lineno = event.lineno;
        if (typeof event.colno === 'number') context.colno = event.colno;
        if (err instanceof Error && err.stack) context.stack = err.stack;
        batcher.push({ level: 'error', module: 'window', message, context: Object.keys(context).length ? context : undefined });
    };
    const onRejection = (event: Event) => {
        const reason = (event as unknown as { reason?: unknown }).reason;
        const message = reason instanceof Error ? reason.message : safeStringify(reason);
        const context: Record<string, unknown> = {};
        if (reason instanceof Error && reason.stack) context.stack = reason.stack;
        batcher.push({
            level: 'error',
            module: 'window',
            message: `Unhandled promise rejection: ${message}`,
            context: Object.keys(context).length ? context : undefined,
        });
    };
    const onPageHide = () => {
        // pagehide fires sync; the IDB transaction is async but starts before
        // the lifecycle event resolves, which is good enough for a dev tool.
        void batcher.flushNow();
    };

    window.addEventListener('error', onError as EventListener);
    window.addEventListener('unhandledrejection', onRejection as EventListener);
    window.addEventListener('pagehide', onPageHide);
    cleanupFns.push(() => {
        window.removeEventListener('error', onError as EventListener);
        window.removeEventListener('unhandledrejection', onRejection as EventListener);
        window.removeEventListener('pagehide', onPageHide);
    });

    return batcher;
}

/** Test-only: undo console patching and reset the singleton. */
export function resetClientLogCaptureForTests(): void {
    for (const fn of cleanupFns) fn();
    cleanupFns = [];
    installed = false;
    singleton = null;
}

function buildEntryFromArgs(level: LogLevel, module: string, args: unknown[]): ClientLogInput {
    if (args.length === 0) return { level, module, message: '' };
    const [first, ...rest] = args;
    const message = typeof first === 'string' ? first : safeStringify(first);
    if (rest.length === 0) return { level, module, message };
    return {
        level,
        module,
        message,
        context: { args: rest.map(safeClone) },
    };
}

function safeStringify(value: unknown): string {
    try {
        if (typeof value === 'string') return value;
        return JSON.stringify(value, circularReplacer()) ?? String(value);
    } catch {
        return String(value);
    }
}

function safeClone(value: unknown): unknown {
    try {
        return JSON.parse(JSON.stringify(value, circularReplacer()));
    } catch {
        return String(value);
    }
}

function circularReplacer(): (key: string, value: unknown) => unknown {
    const seen = new WeakSet<object>();
    return (_key, value) => {
        if (value instanceof Error) {
            return { name: value.name, message: value.message, stack: value.stack };
        }
        if (typeof value === 'object' && value !== null) {
            if (seen.has(value)) return '[Circular]';
            seen.add(value);
        }
        return value;
    };
}

export { ClientLogBatcher };
